using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change: discriminator property renamed to "$type".
            // Preserve "Discriminator" so existing 500K documents remain readable
            // and direct SQL queries (WHERE c.Discriminator = ...) keep working.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // EF Core 9 breaking change: id format changed from "EntityName|Key" to just "Key".
            // Preserve legacy format so existing documents ("Product|123") are found.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            entity.HasIndex(p => p.Sku);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

